SELECT n.name, n.description
FROM networks n
WHERE n.network_avg_degree = (
    SELECT MAX(network_avg_degree) 
    FROM networks
);

SELECT network_size
FROM networks
WHERE network_avg_degree > 5;

SELECT n.name
FROM networks n
WHERE n.network_avg_degree = (
    SELECT MAX(network_avg_degree)
    FROM networks
);

SELECT name, network_avg_degree
FROM networks
WHERE network_avg_degree = (
    SELECT MAX(network_avg_degree)
    FROM networks
);
